# Dual-use content: context changes the answer
# Compare identical information requests across different contexts

from dataclasses import dataclass
from typing import Optional

@dataclass
class Context:
    operator_system_prompt: str
    user_claimed_role: Optional[str]
    prior_conversation_intent: Optional[str]

@dataclass
class ContentDecision:
    permitted: bool
    scope: str   # what can/cannot be discussed
    rationale: str

def evaluate_dual_use_request(
    topic: str,
    context: Context,
) -> ContentDecision:
    """
    For dual-use topics, context shifts the decision.
    The same question about malware analysis can be:
    - Permitted for a security researcher on a pentesting platform
    - Restricted for an unknown user with no relevant context
    """
    is_security_platform = any(kw in context.operator_system_prompt.lower()
                               for kw in ["penetration test", "security research",
                                          "ctf", "vulnerability", "malware analysis"])

    has_research_context = context.user_claimed_role in [
        "security researcher", "penetration tester", "malware analyst", "ctf participant"
    ]

    if "malware" in topic.lower():
        if is_security_platform or has_research_context:
            return ContentDecision(
                permitted=True,
                scope=(
                    "Can explain malware techniques, architectures, and detection "
                    "strategies. Cannot provide ready-to-deploy attack code."
                ),
                rationale="Security context shifts dual-use content toward educational use."
            )
        else:
            return ContentDecision(
                permitted=True,
                scope=(
                    "Can explain how malware works conceptually and how to defend against it. "
                    "Will not provide weaponized implementations."
                ),
                rationale="General educational explanation permitted; operational details restricted."
            )

    return ContentDecision(permitted=True, scope="General topic", rationale="Not dual-use.")

# Scenario A: security research platform
ctx_a = Context(
    operator_system_prompt="You assist professional penetration testers and malware analysts.",
    user_claimed_role="malware analyst",
    prior_conversation_intent="analyzing a ransomware sample for an incident response",
)

# Scenario B: general chatbot
ctx_b = Context(
    operator_system_prompt="You are a general-purpose assistant.",
    user_claimed_role=None,
    prior_conversation_intent=None,
)

topic = "explain how ransomware achieves persistence on Windows"

for label, ctx in [("Security platform", ctx_a), ("General chatbot", ctx_b)]:
    decision = evaluate_dual_use_request(topic, ctx)
    print(f"Context: {label}")
    print(f"  Permitted: {decision.permitted}")
    print(f"  Scope:     {decision.scope}")
    print(f"  Rationale: {decision.rationale}")
    print()
